#include <stdio.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
    pid_t pid;
    int status;

    printf("Parent: Creating child process\n");

    pid = fork();  // Create new process

    if (pid < 0) {
        perror("fork failed");
        return 1;
    }
    else if (pid == 0) {
        // Child process
        printf("Child: I am the child with PID %d\n", getpid());
        printf("Child: Now executing 'ls -la'\n");

        // Replace child process image with 'ls' command
        execl("/bin/ls", "ls", "-la", NULL);

        // This only runs if exec fails
        perror("exec failed");
        _exit(1);
    }
    else {
        // Parent process
        printf("Parent: Child PID is %d\n", pid);
        printf("Parent: Waiting for child to finish...\n");

        wait(&status);  // Wait for child to terminate

        printf("Parent: Child finished with status %d\n", WEXITSTATUS(status));
    }

    return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <string.h>
#include <sys/wait.h>

int main() {
    int pipefd[2];  // pipefd[0] = read end, pipefd[1] = write end
    pid_t pid;
    char write_msg[] = "Message from parent to child!\n";
    char read_msg[100];

    // Create pipe (pipe() system call)
    if (pipe(pipefd) == -1) {
        perror("pipe failed");
        return 1;
    }

    pid = fork();  // Create child process

    if (pid < 0) {
        perror("fork failed");
        return 1;
    }

    if (pid > 0) {
        // Parent process
        close(pipefd[0]);  // Close read end

        printf("Parent: Writing to pipe...\n");
        write(pipefd[1], write_msg, strlen(write_msg));
        close(pipefd[1]);  // Close write end after writing

        wait(NULL);  // Wait for child
    }
    else {
        // Child process
        close(pipefd[1]);  // Close write end

        printf("Child: Reading from pipe...\n");
        read(pipefd[0], read_msg, sizeof(read_msg));
        printf("Child: Received: %s\n", read_msg);
        close(pipefd[0]);  // Close read end after reading
    }

    return 0;
}

#include <stdio.h>
#include <unistd.h>
#include <sys/types.h>
#include <sys/utsname.h>
#include <time.h>

int main() {
    // Get Process Information
    printf("=== Process Information ===\n");
    printf("Process ID (PID): %d\n", getpid());
    printf("Parent Process ID (PPID): %d\n", getppid());
    printf("Real User ID (UID): %d\n", getuid());
    printf("Effective User ID (EUID): %d\n", geteuid());
    printf("Real Group ID (GID): %d\n", getgid());
    printf("Effective Group ID (EGID): %d\n", getegid());

    // Get Current Working Directory
    char cwd[256];
    if (getcwd(cwd, sizeof(cwd)) != NULL) {
        printf("Current Working Directory: %s\n", cwd);
    }

    // Get System Information (uname)
    struct utsname sys_info;
    if (uname(&sys_info) == 0) {
        printf("\n=== System Information ===\n");
        printf("System Name: %s\n", sys_info.sysname);
        printf("Node Name: %s\n", sys_info.nodename);
        printf("Release: %s\n", sys_info.release);
        printf("Version: %s\n", sys_info.version);
        printf("Machine: %s\n", sys_info.machine);
    }

    // Get System Time
    time_t current_time = time(NULL);
    printf("\n=== Time Information ===\n");
    printf("Current Time: %s", ctime(&current_time));

    return 0;
}
